package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.invocation.InvocationOnMock;
import org.mockito.stubbing.Answer;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() {
        String formatted = csvFormat.format("value1", "value2", "value3");
        assertNotNull(formatted);
        assertTrue(formatted.contains("value1"));
        assertTrue(formatted.contains("value2"));
        assertTrue(formatted.contains("value3"));
    }

    @Test
    public void testFormatWithEmptyValues() {
        String formatted = csvFormat.format();
        assertNotNull(formatted);
        assertEquals("", formatted);
    }

    @Test
    public void testFormatWithNullValues() {
        String formatted = csvFormat.format((Object) null);
        assertNotNull(formatted);
        assertEquals("", formatted);
    }

    @Test
    public void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Create a proxy CSVPrinter that throws IOException on printRecord
        Class<?> csvPrinterClass = CSVPrinter.class;

        Constructor<?> constructor = csvPrinterClass.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVPrinter proxyPrinter = (CSVPrinter) Proxy.newProxyInstance(
                csvPrinterClass.getClassLoader(),
                new Class<?>[]{csvPrinterClass},
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("IO error");
                        }
                        // For other methods, do nothing or default
                        if (method.getReturnType().isPrimitive()) {
                            if (method.getReturnType() == boolean.class) {
                                return false;
                            } else if (method.getReturnType() == int.class) {
                                return 0;
                            } else if (method.getReturnType() == long.class) {
                                return 0L;
                            } else if (method.getReturnType() == float.class) {
                                return 0f;
                            } else if (method.getReturnType() == double.class) {
                                return 0d;
                            } else if (method.getReturnType() == byte.class) {
                                return (byte) 0;
                            } else if (method.getReturnType() == short.class) {
                                return (short) 0;
                            } else if (method.getReturnType() == char.class) {
                                return (char) 0;
                            }
                        }
                        return null;
                    }
                });

        // Use reflection to replace the CSVFormat.format method's internal CSVPrinter creation with our proxy
        // Since we cannot change CSVFormat, we use a subclass to override format

        CSVFormat csvFormatWithMockPrinter = new CSVFormat(DEFAULT_DELIMITER,
                DEFAULT_QUOTE_CHAR,
                null,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false,
                false) {
            @Override
            public String format(final Object... values) {
                final StringWriter out = new StringWriter();
                try {
                    // Use the proxyPrinter instead of new CSVPrinter()
                    proxyPrinter.printRecord(values);
                    return out.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatWithMockPrinter.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    // constants from CSVFormat.DEFAULT to construct the subclass
    private static final char DEFAULT_DELIMITER = ',';
    private static final Character DEFAULT_QUOTE_CHAR = '"';
}
